                        node.upsertWhitespaceAfterMe(" ")
                    }
                }
            }
    }

    private fun wouldExceedMaxLineLength(
        colonNode: ASTNode,
        whiteSpaceAfterColon: ASTNode?,
    ): Boolean {
        // If max line length is disabled, don't check
        if (maxLineLength <= 0 || maxLineLength == Int.MAX_VALUE) {
            return false
        }

        // Only check if there's a newline in the whitespace after colon
        if (whiteSpaceAfterColon?.text?.contains('\n') != true) {
            return false
        }

        // Calculate what the line length would be if we put return type on same line
        // Current column of colon + length of ": " + length of return type (everything up to next newline or end of line)
        val colonColumn = colonNode.column

        // Find the return type - it's the next non-whitespace node after the colon
        val returnTypeNode = colonNode.nextLeaf { it.elementType != WHITE_SPACE } ?: return false

        // Calculate the length of the return type text up to the opening brace or end
        var lengthOfReturnType = 0
        var currentNode: ASTNode? = returnTypeNode
        while (currentNode != null) {
            // Stop at newline, opening brace, or equals sign
            if (currentNode.text.contains('\n')) {
                break
            }
            if (currentNode.text in listOf("{", "=")) {
                break
            }
            lengthOfReturnType += currentNode.textLength
            currentNode = currentNode.nextLeaf()
        }

        // Projected line length = current column of colon + ": " (2 chars) + return type length
        val projectedLength = colonColumn + 1 + lengthOfReturnType

        return projectedLength > maxLineLength
    }"}

