    @Test
    fun `Given a function signature with a newline between colon and return type that would exceed max line length, keep the newline`() {
        val code =
            """
            fun thisIsAVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryVeryLongFunction():
