            .hasNoLintViolations()
    }

    @Test
    fun `Given a function signature with a newline between colon and return type that would NOT exceed max line length, reformat to single line`() {
        val code =
            """
            fun shortFunction():
                String {

            }
            """.trimIndent()
        val formattedCode =
            """
            fun shortFunction(): String {

            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
            .hasLintViolation(1, 20, "Single space expected between colon and return type")
            .isFormattedAs(formattedCode)
    }

